import{_ as s,o,c as a,ag as i}from"./chunks/framework.DGzMGr_a.js";const h=JSON.parse('{"title":"同源策略与跨域解决方案","description":"","frontmatter":{"title":"同源策略与跨域解决方案","difficulty":"medium","tags":["同源策略","跨域","CORS","JSONP","postMessage"],"estimate":25},"headers":[],"relativePath":"domains/browser/qa/qa-08-same-origin-cors.md","filePath":"domains/browser/qa/qa-08-same-origin-cors.md","lastUpdated":1783504823000}'),n={name:"domains/browser/qa/qa-08-same-origin-cors.md"};function l(t,e,c,r,d,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="问答-08-进阶-同源策略与跨域解决方案" tabindex="-1">问答 08（进阶）：同源策略与跨域解决方案 <a class="header-anchor" href="#问答-08-进阶-同源策略与跨域解决方案" aria-label="Permalink to &quot;问答 08（进阶）：同源策略与跨域解决方案&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>同源策略是什么？为什么浏览器要设计它？常见的跨域解决方案有哪些（CORS / JSONP / nginx 反向代理 / postMessage / document.domain / WebSocket 等），它们分别适合什么场景？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>什么是同源</strong></p><ul><li>同源 = <strong>协议 + 域名 + 端口</strong> 三者完全相同。 <ul><li><code>https://a.com</code> 与 <code>http://a.com</code>：不同源（协议不同）。</li><li><code>https://a.com</code> 与 <code>https://b.a.com</code>：不同源（域名不同）。</li><li><code>https://a.com</code> 与 <code>https://a.com:8443</code>：不同源（端口不同）。</li></ul></li></ul><p><strong>同源策略限制什么</strong></p><ul><li><strong>DOM 访问</strong>：非同源 iframe 的 <code>contentWindow.document</code> 读不到。</li><li><strong>JS 读取跨源响应</strong>：<code>XHR</code> / <code>fetch</code> 能发出去，但没有 CORS 授权就读不到 body（能 hit 但看不到）。</li><li><strong>Cookie / storage / IndexedDB</strong> 按源隔离。</li><li><strong>不受限</strong>：加载资源（<code>&lt;img&gt;</code>、<code>&lt;script&gt;</code>、<code>&lt;link&gt;</code>、<code>&lt;video&gt;</code>）跨源可读取「不透明结果」（能显示能执行，但 JS 拿不到具体像素/文本，如 canvas 会被污染）。表单可 <code>POST</code> 到跨域。</li></ul><p><strong>为什么要有同源策略</strong></p><ul><li>防止恶意站点直接读取用户在其它站点的敏感数据（银行余额、企业内网）。</li><li>保护 Cookie 自动携带的机制不被滥用（配合 CORS / SameSite）。</li></ul><p><strong>常见跨域方案</strong></p><p><strong>1. CORS（推荐）</strong></p><ul><li>服务器返回 <code>Access-Control-Allow-Origin</code> 授权前端读取跨源响应。</li><li>简单请求（GET / HEAD / POST + 有限 header + 简单 Content-Type）直接发；复杂请求先发 <code>OPTIONS</code> 预检。</li><li>支持凭证（Cookie）时前端 <code>credentials: &#39;include&#39;</code> + 后端 <code>Access-Control-Allow-Credentials: true</code>，且 <code>Allow-Origin</code> 不能是 <code>*</code>。</li><li>详见 CORS 专题（下一题）。</li></ul><p><strong>2. JSONP（历史方案）</strong></p><ul><li>利用 <code>&lt;script src=&quot;...&quot;&gt;</code> 不受同源限制的特性。</li><li>前端插入 script 标签，src 里带回调名 <code>?callback=cb123</code>；服务端返回 <code>cb123({...})</code> 这样一段可执行 JS。</li><li>只能 GET，安全性差（依赖执行任意 JS，易被 XSS / DNS 污染），基本已淘汰。</li></ul><p><strong>3. Nginx 反向代理</strong></p><ul><li>前端把请求发到自己域名，Nginx 内部转发到跨域后端。</li><li>前端视角是同源，浏览器不介入 CORS。</li><li>常用于开发环境（Vite / webpack 的 <code>proxy</code>）和公司内部网关聚合。</li></ul><div class="language-nginx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /api/ </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">https://backend.other.com/;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host backend.other.com;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>4. postMessage</strong></p><ul><li>用于<strong>跨窗口 / iframe</strong> 通信（不是普通 XHR）。</li><li><code>otherWindow.postMessage(data, targetOrigin)</code>，对端 <code>window.addEventListener(&#39;message&#39;, e =&gt; ...)</code>。</li><li>一定要校验 <code>event.origin</code> 和 <code>event.source</code>，否则任意页面都能给你发消息。</li></ul><p><strong>5. document.domain（已废弃 / 部分浏览器已默认禁用）</strong></p><ul><li>只对<strong>主域相同</strong>的子域（如 <code>a.example.com</code> 与 <code>b.example.com</code>）有效，双方都把 <code>document.domain = &#39;example.com&#39;</code> 即可访问对方 DOM。</li><li>Chrome 已默认禁用，需要 <code>Origin-Agent-Cluster: ?0</code> 才能生效，未来会移除。用 <code>postMessage</code> 替代。</li></ul><p><strong>6. WebSocket</strong></p><ul><li>WebSocket 协议本身不受同源策略限制（握手时能带任意 Origin），服务端自己校验。</li></ul><p><strong>7. window.name / location.hash（历史 hack）</strong></p><ul><li>iframe 里的 <code>window.name</code> 或 <code>#hash</code> 变化能跨域读到，配合中转页做通信。已被 <code>postMessage</code> 完全取代。</li></ul><p><strong>8. Service Worker 拦截</strong></p><ul><li>在 SW 里代理请求或伪造响应，某些场景可以绕过 CORS（但仍受 CORS 影响，SW 只是转发）。</li></ul><h2 id="追问-1-同源策略下-img-、-script-可以跨源加载-那为什么-canvas-会被「污染」" tabindex="-1">追问 1：同源策略下，<code>&lt;img&gt;</code>、<code>&lt;script&gt;</code> 可以跨源加载，那为什么 <code>&lt;canvas&gt;</code> 会被「污染」？ <a class="header-anchor" href="#追问-1-同源策略下-img-、-script-可以跨源加载-那为什么-canvas-会被「污染」" aria-label="Permalink to &quot;追问 1：同源策略下，\`&lt;img&gt;\`、\`&lt;script&gt;\` 可以跨源加载，那为什么 \`&lt;canvas&gt;\` 会被「污染」？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>跨源图片能显示，但 canvas 一旦画了跨源图片就变「污染（tainted）」，<code>toDataURL</code> / <code>getImageData</code> 抛安全错误。</li><li>目的：防止页面把跨源图片（可能包含敏感信息，如用户头像）作为像素读取出来，绕过同源策略。</li><li>解决：图片资源加 <code>crossorigin=&quot;anonymous&quot;</code>（不带 Cookie）或 <code>use-credentials</code>，同时服务器返回 <code>Access-Control-Allow-Origin</code>，浏览器就允许 canvas 读取像素。</li><li>类似还有跨源 audio / video 元素默认无法读取 <code>captureStream()</code>、<code>WebGL</code> 里的跨源纹理也会被限制。</li></ul><h2 id="追问-2-cors-预检-preflight-到底在做什么-什么情况下会触发" tabindex="-1">追问 2：CORS 预检（Preflight）到底在做什么？什么情况下会触发？ <a class="header-anchor" href="#追问-2-cors-预检-preflight-到底在做什么-什么情况下会触发" aria-label="Permalink to &quot;追问 2：CORS 预检（Preflight）到底在做什么？什么情况下会触发？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>预检就是浏览器在真正请求前先发一个 <code>OPTIONS</code>，询问服务器允不允许这个跨域请求。</li><li>触发条件（<strong>不是简单请求</strong>就要预检）： <ul><li>方法不是 GET / HEAD / POST。</li><li>带自定义头（<code>Authorization</code>、<code>X-Token</code> 等）。</li><li><code>Content-Type</code> 不是 <code>application/x-www-form-urlencoded</code> / <code>multipart/form-data</code> / <code>text/plain</code>（例如 <code>application/json</code>）。</li><li><code>ReadableStream</code> body、<code>fetch</code> 请求带 <code>keepalive</code> 等特殊情形。</li></ul></li><li>预检报文：</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OPTIONS /api HTTP/1.1</span></span>
<span class="line"><span>Origin: https://a.com</span></span>
<span class="line"><span>Access-Control-Request-Method: POST</span></span>
<span class="line"><span>Access-Control-Request-Headers: Content-Type, X-Token</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>服务器回：</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP/1.1 204 No Content</span></span>
<span class="line"><span>Access-Control-Allow-Origin: https://a.com</span></span>
<span class="line"><span>Access-Control-Allow-Methods: POST</span></span>
<span class="line"><span>Access-Control-Allow-Headers: Content-Type, X-Token</span></span>
<span class="line"><span>Access-Control-Max-Age: 86400</span></span>
<span class="line"><span>Access-Control-Allow-Credentials: true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ul><li><code>Access-Control-Max-Age</code> 让预检结果缓存一段时间，减少 OPTIONS 次数。</li><li>若预检失败，浏览器直接报 CORS 错误，真正请求根本不发。</li></ul><h2 id="追问-3-如果后端只允许指定几个域名跨域-怎么写既安全又灵活的-cors-配置" tabindex="-1">追问 3：如果后端只允许指定几个域名跨域，怎么写既安全又灵活的 CORS 配置？ <a class="header-anchor" href="#追问-3-如果后端只允许指定几个域名跨域-怎么写既安全又灵活的-cors-配置" aria-label="Permalink to &quot;追问 3：如果后端只允许指定几个域名跨域，怎么写既安全又灵活的 CORS 配置？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>不要直接把 <code>Access-Control-Allow-Origin: *</code></strong>（尤其带 Cookie 时更不允许，浏览器会拒绝）。</li><li>后端读取请求的 <code>Origin</code>，与白名单比对： <ul><li>若匹配 → <code>Access-Control-Allow-Origin: &lt;该 Origin&gt;</code> + <code>Vary: Origin</code>。</li><li>不匹配 → 不返回 CORS 头（浏览器会拒绝）或返回 4xx。</li></ul></li><li>加上 <code>Vary: Origin</code> 让 CDN / 缓存不会把 A 域的响应错发给 B 域。</li><li>通配符 <code>*.example.com</code> 需要自己匹配，规范里没有子域通配。</li><li>谨慎放开 <code>Access-Control-Allow-Credentials: true</code>，此时 Origin 必须精确匹配。</li><li>定期审计白名单，避免历史遗留域名被抢注后变成 CSRF 通道。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://fetch.spec.whatwg.org/" target="_blank" rel="noreferrer">Fetch Living Standard</a>：CORS 与请求/响应模型</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Guides/CORS" target="_blank" rel="noreferrer">MDN: CORS</a>：跨域资源共享机制</li><li><a href="https://web.dev/articles/same-origin-policy" target="_blank" rel="noreferrer">web.dev: Same-origin policy</a>：同源策略与跨域方案</li></ul>`,44)])])}const u=s(n,[["render",l]]);export{h as __pageData,u as default};
